def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
  import scala.collection.mutable

  val depthMap = new mutable.HashMap[Long, Int]()

  // Function to compute popcount-depth
  def getDepth(x: Long): Int = {
    var d = 0
    var xCopy = x
    while (xCopy > 0) {
      xCopy = xCopy >> 1
      d += 1
      if (xCopy == 0) break
    }
    d
  }

  // Precompute depth for each number in nums
  for (num <- nums) {
    val d = getDepth(num)
    depthMap.put(num, d)
  }

  // For efficient range queries, we use a segment tree
  class SegmentTree(val data: Array[Int]) {
    val n = data.length
    val size = 1
    while (size < n) size <<= 1
    val tree = new Array[Int](size * 2)
    // Initialize leaves
    for (i <- 0 until n) {
      tree(size + i) = data(i)
    }
    // Build the tree
    for (i <- size - 1 downTo 1) {
      tree(i) = tree(2 * i) + tree(2 * i + 1)
    }

    def get(n: Int): Int = {
      var res = 0
      var nCopy = n + size
      while (nCopy > 0) {
        res += tree(nCopy)
        nCopy >>= 1
      }
      res
    }

    def update(pos: Int, value: Int): Unit = {
      var posCopy = pos + size
      tree(posCopy) = value
      posCopy >>= 1
      while (posCopy > 0) {
        tree(posCopy) = tree(2 * posCopy) + tree(2 * posCopy + 1)
        posCopy >>= 1
      }
    }

    def rangeQuery(l: Int, r: Int): Int = {
      var res = 0
      var lCopy = l + size
      var rCopy = r + size
      while (lCopy <= rCopy) {
        if (lCopy % 2 == 1) {
          res += tree(lCopy)
          lCopy += 1
        }
        if (rCopy % 2 == 0) {
          res += tree(rCopy)
          rCopy -= 1
        }
        lCopy >>= 1
        rCopy >>= 1
      }
      res
    }
  }

  // Initialize segment tree with the precomputed depths
  val st = new SegmentTree(Array.fill(nums.length)(depthMap.getOrElse(nums(0), 0)))

  val answer = new Array[Long](queries.length)

  for (i <- 0 until queries.length) {
    val query = queries(i)
    if (query(0) == 1) {
      val [_, l, r, k] = query
      val count = st.rangeQuery(l, r)
      answer(i) = count
    } else {
      val [_, idx, val] = query
      // Update the value in nums
      nums(idx) = val
      // Recompute the depth for this value
      val d = getDepth(val)
      // Update the segment tree
      st.update(idx, d)
    }
  }

  answer
}
