      var res = 0
      var lCopy = l + size
      var rCopy = r + size
      while (lCopy <= rCopy) {
        if (lCopy % 2 == 1) {
          res += tree(lCopy)
          lCopy += 1
        }
        if (rCopy % 2 == 0) {
          res += tree(rCopy)
          rCopy -= 1
        }
        lCopy >>= 1
        rCopy >>= 1
      }
      res
    }
  }

  // Initialize segment tree with the precomputed depths
  val st = new SegmentTree(depthMap.values.toArray)

  val answer = scala.collection.mutable.ArrayBuffer[Long]()

  for (query <- queries) {
    if (query(0) == 1) {
      val (_, l, r, k) = query
      val count = st.rangeQuery(l, r)
      answer += count
    } else {
      val (_, idx, val_) = query
      // Update the value in nums
      nums(idx) = val_
      // Recompute the depth for this value
      val d = getDepth(val_)
      // Update the segment tree
      st.update(idx, d)
    }
  }

  answer.toArray
}
