```typescript
function solve(nums: number[], queries: number[][]): number[] {
    // Precompute popcount-depth for each number in nums
    const depthMap = new Map<number, number>();
    const maxDepth = 5; // Since k is up to 5, we only need to track up to depth 5

    // Function to compute popcount-depth
    function getDepth(x: number): number {
        let d = 0;
        while (x > 0) {
            x = x >> 1;
            d++;
            if (x === 0) break;
        }
        return d;
    }

    // Precompute depth for each number in nums
    for (const num of nums) {
        let x = num;
        let d = 0;
        while (x > 0) {
            x = x >> 1;
            d++;
            if (x === 0) break;
        }
        depthMap.set(num, d);
    }

    // For efficient range queries, we use a segment tree
    class SegmentTree {
        constructor(private data: number[]) {
            this.n = data.length;
            this.size = 1;
            while (this.size < this.n) this.size <<= 1;
            this.tree = new Array(this.size).fill(0);
            // Initialize leaves
            for (let i = 0; i < this.n; i++) {
                this.tree[this.size + i] = data[i];
            }
            // Build the tree
            for (let i = this.size - 1; i > 0; i--) {
                this.tree[i] = this.tree[2 * i] + this.tree[2 * i + 1];
            }
        }

        get(n: number): number {
            let res = 0;
            n += this.size;
            while (n > 0) {
                res += this.tree[n];
                n >>= 1;
            }
            return res;
        }

        update(pos: number, value: number): void {
            pos += this.size;
            this.tree[pos] = value;
            pos >>= 1;
            while (pos > 0) {
                this.tree[pos] = this.tree[2 * pos] + this.tree[2 * pos + 1];
                pos >>= 1;
            }
        }

        rangeQuery(l: number, r: number): number {
            let res = 0;
            l += this.size;
            r += this.size;
            while (l <= r) {
                if (l % 2 === 1) {
                    res += this.tree[l];
                    l++;
                }
                if (r % 2 === 0) {
                    res += this.tree[r];
                    r--;
                }
                l >>= 1;
                r >>= 1;
            }
            return res;
        }

        private n: number;
        private size: number;
        private tree: number[];
    }

    // Initialize segment tree with the precomputed depths
    const st = new SegmentTree(Array.from(depthMap.values()));

    const answer: number[] = [];

    for (const query of queries) {
        if (query[0] === 1) {
            const [_, l, r, k] = query;
            const count = st.rangeQuery(l, r);
            answer.push(count);
        } else {
            const [_, idx, val] = query;
            // Update the value in nums
            nums[idx] = val;
            // Recompute the depth for this value
            let x = val;
            let d = 0;
            while (x > 0) {
                x = x >> 1;
                d++;
                if (x === 0) break;
            }
            // Update the segment tree
            st.update(idx, d);
        }
    }

    return answer;
}
